import argparse
from pathlib import Path
HTML = '<!doctype html>\n<html>\n<head>\n  <meta charset="utf-8"/>\n  <title>Human Audit (all models)</title>\n  <style>\n    body { font-family: Arial, sans-serif; margin: 16px; }\n    .row { display:flex; gap:16px; align-items:flex-start; }\n    .panel { flex: 1; }\n    img { max-width: 100%; border: 1px solid #ddd; }\n    textarea { width: 100%; height: 110px; }\n    .meta { color:#333; font-size: 14px; margin: 6px 0; }\n    .btn { padding: 8px 12px; margin-right: 8px; }\n    .pill { display:inline-block; padding:2px 8px; border:1px solid #aaa; border-radius:999px; font-size:12px; margin-right:6px; }\n    .box { border: 1px solid #ddd; padding: 8px; border-radius: 6px; margin-top: 8px; }\n    .small { font-size: 13px; }\n    .tag { display:inline-block; padding:1px 6px; border:1px solid #aaa; border-radius:6px; font-size:12px; margin-left:6px; }\n    .ok { border-color:#2a8f2a; color:#2a8f2a; }\n    .bad { border-color:#b33434; color:#b33434; }\n    ul { margin: 6px 0 0 20px; padding:0; }\n    li { margin: 2px 0; }\n    .mono { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace; }\n    details { margin-top: 8px; }\n    summary { cursor: pointer; font-weight: bold; }\n    table { border-collapse: collapse; width: 100%; }\n    td { padding: 4px 8px; vertical-align: top; }\n    .top { display:flex; gap:12px; align-items:center; flex-wrap:wrap; }\n  </style>\n</head>\n<body>\n<h2>Human Audit: Slides + All-Model Outputs (with grounding/valid flags)</h2>\n\n<div class="top meta">\n  <div>\n    1) Choose <span class="pill">audit_packets_full.json</span>\n    <input type="file" id="pktFile" accept=".json"/>\n  </div>\n  <div>\n    2) Choose folder <span class="pill">audit_images/</span>\n    <input type="file" id="imgFolder" webkitdirectory directory multiple />\n  </div>\n</div>\n\n<div>\n  <button class="btn" id="btnPrev" disabled>Prev</button>\n  <button class="btn" id="btnNext" disabled>Next</button>\n  <button class="btn" id="btnSave" disabled>Download responses CSV</button>\n  <span id="status" class="meta"></span>\n</div>\n\n<hr/>\n\n<div class="row">\n  <div class="panel">\n    <div id="meta"></div>\n    <img id="slideImg" alt="Slide image"/>\n  </div>\n\n  <div class="panel">\n    <h3>Outputs to judge</h3>\n    <div id="modelsBox"></div>\n\n    <details>\n      <summary>Consensus view (optional)</summary>\n      <div class="box">\n        <div class="meta"><b>Consensus concepts</b></div>\n        <div id="consConcepts" class="small"></div>\n      </div>\n      <div class="box">\n        <div class="meta"><b>Consensus triples</b></div>\n        <div id="consTriples" class="small"></div>\n      </div>\n    </details>\n\n    <h3>Labels</h3>\n    <table>\n      <tr><td>Concepts correct/useful?</td>\n        <td>\n          <select id="qConcept">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td></tr>\n      <tr><td>Triples correct/useful?</td>\n        <td>\n          <select id="qTriple">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td></tr>\n      <tr><td>Key info mainly in image?</td>\n        <td>\n          <select id="qImageDominant">\n            <option value="">(skip)</option>\n            <option value="yes">yes</option>\n            <option value="no">no</option>\n          </select>\n        </td></tr>\n    </table>\n\n    <h3>Notes (optional)</h3>\n    <textarea id="notes" placeholder="Optional: mention which model(s) were wrong, paraphrase issues, etc."></textarea>\n  </div>\n</div>\n\n<script>\nfunction toCSV(rows){\n  if(rows.length===0) return "";\n  const header = Object.keys(rows[0]);\n  const lines = [header.join(",")];\n  for(const r of rows){\n    const line = header.map(h => (r[h]??"").toString().replaceAll("\\n"," ").replaceAll(",",";"));\n    lines.push(line.join(","));\n  }\n  return lines.join("\\n");\n}\n\nlet packets = [];\nlet idx = 0;\nlet responses = {};\nlet imgMap = new Map();\n\nfunction keyOf(p){ return `${p.lecture}__${p.slide_id}`; }\n\nfunction setEnabled(on){\n  document.getElementById("btnPrev").disabled = !on;\n  document.getElementById("btnNext").disabled = !on;\n  document.getElementById("btnSave").disabled = !on;\n}\n\nfunction renderConceptList(concepts){\n  if(!concepts || concepts.length===0) return "<div class=\'meta\'>No concepts.</div>";\n  let html = "<ul>";\n  for(const c of concepts){\n    const g = c.grounding || "unknown";\n    html += `<li><span class="mono">${c.term}</span> · ${c.category||""} · <span class="tag">${g}</span></li>`;\n  }\n  html += "</ul>";\n  return html;\n}\n\nfunction renderTripleList(triples){\n  if(!triples || triples.length===0) return "<div class=\'meta\'>No triples.</div>";\n  let html = "<ul>";\n  for(const t of triples){\n    const v = (t.triple_valid==1) ? "valid" : "invalid";\n    const cls = (t.triple_valid==1) ? "ok" : "bad";\n    const ev = (t.evidence||"").toString();\n    html += `<li><span class="mono">(${t.s} , ${t.p} , ${t.o})</span> · <span class="tag ${cls}">${v}</span>\n             <div class="small">evidence: ${ev}</div></li>`;\n  }\n  html += "</ul>";\n  return html;\n}\n\nfunction renderConsensusConcepts(p){\n  if(!p.consensus_concepts || p.consensus_concepts.length===0) return "<div class=\'meta\'>No consensus concepts.</div>";\n  let html = "<ul>";\n  for(const c of p.consensus_concepts){\n    html += `<li><span class="mono">${c.term}</span> · ${c.category||""} · support=${c.support} · <span class="tag">${c.grounding_majority||"unknown"}</span></li>`;\n  }\n  html += "</ul>";\n  return html;\n}\nfunction renderConsensusTriples(p){\n  if(!p.consensus_triples || p.consensus_triples.length===0) return "<div class=\'meta\'>No consensus triples.</div>";\n  let html = "<ul>";\n  for(const t of p.consensus_triples){\n    const v = (t.valid_majority==1) ? "valid" : "invalid";\n    const cls = (t.valid_majority==1) ? "ok" : "bad";\n    html += `<li><span class="mono">(${t.s} , ${t.p} , ${t.o})</span> · support=${t.support} · <span class="tag ${cls}">${v}</span>\n             <div class="small">evidence: ${t.evidence||""}</div></li>`;\n  }\n  html += "</ul>";\n  return html;\n}\n\nfunction renderModels(p){\n  const models = p.models || {};\n  let html = "";\n  for(const [m, obj] of Object.entries(models)){\n    html += `<details open>\n      <summary>${m}</summary>\n      <div class="box">\n        <div class="meta"><b>Concepts</b></div>\n        ${renderConceptList(obj.concepts)}\n      </div>\n      <div class="box">\n        <div class="meta"><b>Triples</b></div>\n        ${renderTripleList(obj.triples)}\n      </div>\n    </details>`;\n  }\n  return html;\n}\n\nfunction render(){\n  const p = packets[idx];\n  const k = keyOf(p);\n\n  document.getElementById("meta").innerHTML = `\n    <div class="meta"><b>${p.group}</b> | <b>${p.lecture}</b> / <b>${p.slide_id}</b></div>\n    <div class="meta">image_path: ${p.image_path}</div>\n  `;\n\n  document.getElementById("slideImg").src = imgMap.get(p.image_path) || "";\n\n  document.getElementById("modelsBox").innerHTML = renderModels(p);\n  document.getElementById("consConcepts").innerHTML = renderConsensusConcepts(p);\n  document.getElementById("consTriples").innerHTML = renderConsensusTriples(p);\n\n  const r = responses[k] || {};\n  document.getElementById("qConcept").value = r.concepts || "";\n  document.getElementById("qTriple").value = r.triples || "";\n  document.getElementById("qImageDominant").value = r.image_dominant || "";\n  document.getElementById("notes").value = r.notes || "";\n\n  document.getElementById("status").textContent = `Slide ${idx+1}/${packets.length}`;\n}\n\nfunction saveCurrent(){\n  const p = packets[idx];\n  const k = keyOf(p);\n  responses[k] = {\n    concepts: document.getElementById("qConcept").value,\n    triples: document.getElementById("qTriple").value,\n    image_dominant: document.getElementById("qImageDominant").value,\n    notes: document.getElementById("notes").value,\n  };\n}\n\ndocument.getElementById("btnPrev").onclick = () => { saveCurrent(); idx = Math.max(0, idx-1); render(); };\ndocument.getElementById("btnNext").onclick = () => { saveCurrent(); idx = Math.min(packets.length-1, idx+1); render(); };\n\ndocument.getElementById("btnSave").onclick = () => {\n  saveCurrent();\n  const outRows = packets.map(p => {\n    const k = keyOf(p);\n    const r = responses[k] || {};\n    return {\n      group: p.group,\n      lecture: p.lecture,\n      slide_id: p.slide_id,\n      image_path: p.image_path,\n      concepts_correct: r.concepts || "",\n      triples_correct: r.triples || "",\n      image_dominant: r.image_dominant || "",\n      notes: r.notes || "",\n    };\n  });\n  const blob = new Blob([toCSV(outRows)], {type:"text/csv;charset=utf-8"});\n  const a = document.createElement("a");\n  a.href = URL.createObjectURL(blob);\n  a.download = "audit_responses.csv";\n  a.click();\n};\n\ndocument.getElementById("pktFile").addEventListener("change", async (ev) => {\n  const f = ev.target.files[0];\n  if(!f) return;\n  packets = JSON.parse(await f.text());\n  idx = 0;\n  if(packets.length && imgMap.size){ setEnabled(true); render(); }\n});\n\ndocument.getElementById("imgFolder").addEventListener("change", (ev) => {\n  imgMap = new Map();\n  for(const f of ev.target.files){\n    const rel = f.webkitRelativePath.replaceAll("\\\\","/");\n    imgMap.set(rel, URL.createObjectURL(f));\n  }\n  if(packets.length && imgMap.size){ setEnabled(true); render(); }\n});\n</script>\n</body>\n</html>\n'

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--out', required=True)
    args = ap.parse_args()
    out_dir = Path(args.out)
    out_dir.mkdir(parents=True, exist_ok=True)
    (out_dir / 'audit_form_all_models.html').write_text(HTML, encoding='utf-8')
    print('[OK] Wrote:', out_dir / 'audit_form_all_models.html')
if __name__ == '__main__':
    main()